module reg_16bit(
    input               reset_clk      ,
    input               rst      ,
    input               en       ,
    input [15:0]        data_in  ,
    output reg [15:0]   data_out 
);

always @(posedge reset_clk) begin
    if (rst)
        data_out <= 16'd0;
    else if (en)
        data_out <= data_in;
end

endmodule
